                if(ds_heavy1.getCellData(ds_heavy1.getRowPosition(),"clntNm") == '자사'){
                    gr_heavy1.setHeaderClass("column54", "txt-red");
                    gr_heavy1.setHeaderClass("column45", "txt-red");
